) values (
    #{id}, #{projectId}, #{itemName}, #{description}, #{status}, #{checkerId}, #{checkedAt}, #{remark}, #{createdAt}, #{updatedAt}, 0
)

mapper.update:
update acceptance_item
set is_deleted = 1,
    updated_at = #{updatedAt}
where project_id = #{projectId}
  and id = #{id}
  and is_deleted = 0

